    std::uint64_t *aOrbiterAssignSaltD = pDomainSaltSet->mOrbiterAssign.mSaltD;
    std::uint64_t *aOrbiterAssignSaltE = pDomainSaltSet->mOrbiterAssign.mSaltE;
    std::uint64_t *aOrbiterAssignSaltF = pDomainSaltSet->mOrbiterAssign.mSaltF;
    std::uint64_t *aOrbiterUpdateSaltA = pDomainSaltSet->mOrbiterUpdate.mSaltA;
    std::uint64_t *aOrbiterUpdateSaltB = pDomainSaltSet->mOrbiterUpdate.mSaltB;
    std::uint64_t *aOrbiterUpdateSaltC = pDomainSaltSet->mOrbiterUpdate.mSaltC;
    std::uint64_t *aOrbiterUpdateSaltD = pDomainSaltSet->mOrbiterUpdate.mSaltD;
    std::uint64_t *aOrbiterUpdateSaltE = pDomainSaltSet->mOrbiterUpdate.mSaltE;
    std::uint64_t *aOrbiterUpdateSaltF = pDomainSaltSet->mOrbiterUpdate.mSaltF;
    std::uint64_t *aWandererUpdateSaltA = pDomainSaltSet->mWandererUpdate.mSaltA;
    std::uint64_t *aWandererUpdateSaltB = pDomainSaltSet->mWandererUpdate.mSaltB;
    std::uint64_t *aWandererUpdateSaltC = pDomainSaltSet->mWandererUpdate.mSaltC;
    std::uint64_t *aWandererUpdateSaltD = pDomainSaltSet->mWandererUpdate.mSaltD;
    std::uint64_t *aWandererUpdateSaltE = pDomainSaltSet->mWandererUpdate.mSaltE;
    std::uint64_t *aWandererUpdateSaltF = pDomainSaltSet->mWandererUpdate.mSaltF;
    std::uint8_t *aEarthLaneA = pWorkSpace->mEarthLaneA;
    std::uint8_t *aEarthLaneB = pWorkSpace->mEarthLaneB;
    std::uint8_t *aEarthLaneC = pWorkSpace->mEarthLaneC;
    std::uint8_t *aEarthLaneD = pWorkSpace->mEarthLaneD;
    std::uint8_t *aScrapLaneA = pWorkSpace->mScrapLaneA;
    std::uint8_t *aScrapLaneB = pWorkSpace->mScrapLaneB;
    std::uint64_t aCross = 0; std::uint64_t aScatter = 0;

    std::uint64_t aOrbiterA = 0; std::uint64_t aOrbiterB = 0; std::uint64_t aOrbiterC = 0; std::uint64_t aOrbiterD = 0;
    std::uint64_t aOrbiterE = 0; std::uint64_t aOrbiterF = 0; std::uint64_t aOrbiterG = 0; std::uint64_t aOrbiterH = 0;
    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0xBC57D50F5356A2EFULL + 0xF57D807E6662FE26ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseB(pNonce * 0xFCAC7ED826BE9F6DULL + 0xE4393C7E9271D021ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseB(pNonce * 0xE79D778232A7F28BULL + 0xE741E92E1350B8B3ULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseC(pNonce * 0xBEB99DD921DDCF43ULL + 0x94030989195BD3ABULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseA(pNonce * 0x833962C188DC70C7ULL + 0xA8726B6C4734797FULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseC(pNonce * 0xDB2523B3DF8BCAC5ULL + 0xBA2D5D00813774F1ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xEB53AB7DBFC30E89ULL + 0x8FB178AB2BB66716ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xDA2BDC7B3305A7F5ULL + 0xE9F93740C73D48CBULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0xD1D3B8DF27F1C9ADULL + 0xBFC4E96A863C2898ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0x966FE77847986823ULL + 0xE20CE2406DF1A12AULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0x895CCE228550B70DULL + 0x92A3652477285406ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0x83FC87ED66381973ULL + 0xC03F805F819C313BULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseA(pNonce * 0xC8DA937554346257ULL + 0xF3F9CCC1ECE441A3ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseC(pNonce * 0x8AE65FEB9B28E123ULL + 0xF896D1C77CD9F9A9ULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseC(pNonce * 0xC777361F4261A5F9ULL + 0x80FCAD86517C6A22ULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseB(pNonce * 0xC7252810A5A7D337ULL + 0x89AFE786A24D72B5ULL);
    std::uint64_t aDomainWordIngress = pConstants->mIngress;
    std::uint64_t aDomainWordScatter = pConstants->mScatter;
