            aCross = TwistMix64::DiffuseA(((aCross ^ aDomainWordCross) ^ aNonceWordC));
            //
            aScatter = (RotL64(aPrevious, 12U) ^ RotL64(aCarry, 27U)) + (RotL64(aCross, 53U) + RotL64(aIngress, 39U));
            aScatter = TwistMix64::DiffuseA(((aScatter ^ aDomainWordScatter) ^ aNonceWordA));
            //
            aOrbiterH = (((aWandererJ + RotL64(aIngress, 27U)) + RotL64(aCarry, 47U)) + 4914687152693808355U) + aNonceWordL;
            aOrbiterI = ((aWandererH + RotL64(aPrevious, 13U)) + RotL64(aCarry, 39U)) + 16130066171667588061U;
            aOrbiterB = (aWandererK + RotL64(aCross, 21U)) + 15367227709459137665U;
            aOrbiterD = ((aWandererE + RotL64(aScatter, 18U)) + 3834629493487957155U) + aNonceWordJ;
            aOrbiterJ = (aWandererC + RotL64(aIngress, 53U)) + 7633503432585125254U;
            aOrbiterE = (aWandererI + RotL64(aPrevious, 29U)) + 6948044859355015214U;
            aOrbiterA = ((aWandererA + RotL64(aCross, 5U)) + 3549032307638543762U) + aOrbiterAssignSaltC[(((31U - aIndex) + 26U)) & S_SALT1];
            aOrbiterG = ((aWandererB + RotL64(aScatter, 37U)) + RotL64(aCarry, 23U)) + 2463739870051904037U;
            aOrbiterC = ((aWandererD + RotL64(aIngress, 10U)) + 12916494659730707437U) + aOrbiterAssignSaltB[((aIndex + 19U)) & S_SALT1];
